function toBase(n, b) {
  if (n === 0) return [0];
  const digits = [];
  while (n > 0) {
    digits.push(n % b);
    n = Math.trunc(n / b);
  }
  digits.reverse();
  return digits;
}

function singleNumber(xs) {
  let x = 0;
  for (let i = 0; i < xs.length; i++) x ^= xs[i];
  return x;
}

